                    ) : (
                      <div className="space-y-2">
                        <p className="text-[10px] text-slate-600 uppercase font-medium">Try Riot ID (Name#Tag) for direct deep scanning</p>
                        <p className="text-[9px] text-slate-700 italic">Example: Hide on bush#KR1</p>
                      </div>
                    )}
